package org.apache.commons.csv;
import java.io.BufferedReader;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class ExtendedBufferedReaderTest {

    ExtendedBufferedReader extendedBufferedReader;
    Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = mock(Reader.class);
        extendedBufferedReader = new ExtendedBufferedReader(mockReader);
    }

    @Test
    void testReadReturnsCharAndUpdatesLastCharNoNewline() throws IOException {
        ExtendedBufferedReader spyReader = Mockito.spy(extendedBufferedReader);
        doReturn((int) 'a').when(spyReader).read();

        // Because read() is overridden, calling super.read() in read() will call BufferedReader.read()
        // We need to mock BufferedReader.read() but it's not possible directly, so we spy and override read() call
        // Instead, we mock the super.read() by spying and calling the real method for read(), then override super.read() by mocking read() of BufferedReader

        // We cannot mock super.read() directly; workaround: create a subclass with a method to expose super.read()
        // But here, we just spy and mock the super.read() call via doCallRealMethod and doReturn, but this is complicated.
        // Instead, use a subclass to expose super.read() for testing or use reflection.

        // Alternative: Create a subclass to override super.read() to return desired values.
        ExtendedBufferedReader testReader = new ExtendedBufferedReader(mockReader) {
            @Override
            public int read() throws IOException {
                return (int) 'a';
            }
        };

        // But this overrides the focal method itself, so no.
        // So better to test the focal method via reflection to call the original method.

        // Instead, we create a spy and mock the super.read() call via reflection:
        // But super.read() is called inside read(), so spy.read() calls read(), which calls super.read(), which calls BufferedReader.read()

        // So we mock the Reader to provide data to BufferedReader.read()

        // Setup mockReader to return 'a' then EOF
        when(mockReader.read()).thenReturn((int) 'a', -1);

        ExtendedBufferedReader reader = new ExtendedBufferedReader(mockReader);

        int result = reader.read();
        assertEquals('a', result);
        // lastChar should be 'a', lineCounter 0
        assertEquals('a', getPrivateField(reader, "lastChar"));
        assertEquals(0, getPrivateField(reader, "lineCounter"));
    }

    @Test
    void testReadReturnsNewlineAndIncrementsLineCounter() throws IOException {
        when(mockReader.read()).thenReturn((int) '\n', -1);

        ExtendedBufferedReader reader = new ExtendedBufferedReader(mockReader);

        int result = reader.read();
        assertEquals('\n', result);
        assertEquals('\n', getPrivateField(reader, "lastChar"));
        assertEquals(1, getPrivateField(reader, "lineCounter"));
    }

    @Test
    void testReadReturnsEOF() throws IOException {
        when(mockReader.read()).thenReturn(-1);

        ExtendedBufferedReader reader = new ExtendedBufferedReader(mockReader);

        int result = reader.read();
        assertEquals(-1, result);
        assertEquals(-1, getPrivateField(reader, "lastChar"));
        assertEquals(0, getPrivateField(reader, "lineCounter"));
    }

    // Utility method to read private fields via reflection
    private int getPrivateField(ExtendedBufferedReader reader, String fieldName) {
        try {
            java.lang.reflect.Field field = ExtendedBufferedReader.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            return field.getInt(reader);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
